15→export function escHtml(text: string): string {
16→  return text
17→    .replace(/&/g, '&amp;')
18→    .replace(/</g, '&lt;')
19→    .replace(/>/g, '&gt;')
20→    .replace(/"/g, '&quot;')
21→    .replace(/'/g, '&#39;')
